import React from "react";
import { useSelector } from "react-redux";
import { createSelector } from "reselect";
export default ({ title }) => {
    const router = useSelector(createSelector(({ router }) => router, router => router));
    const init = React.useRef(false);
    const getTitle = () => `SRC · ${title}`;
    const setScroll = (init) => {
        if (window.location.hash) {
            try {
                const el = document.querySelector(window.location.hash);
                if (el) {
                    const timeout = init ? 100 : 0;
                    setTimeout(() => window.scrollTo(0, el.offsetTop - 84), timeout);
                    return;
                }
            }
            catch (ignored) { }
        }
        if (init)
            window.scrollTo(0, 0);
    };
    React.useEffect(() => {
        if (!init.current) {
            init.current = true;
            document.title = getTitle();
            setScroll(true);
        }
        else
            setScroll(false);
    }, [router.url]);
};
